    public void testlikelihoodcomputation(){
        {
            Double[] p = {0.34013311268852675};

//            Utils._PARAMETER_INPUT = Arrays.asList(p);
            List<Alignment> alignments = new ArrayList<>();
            List<UltrametricTree> geneTrees = new ArrayList<>();
            Map<String, String> locus = new HashMap<>();
            locus.put("E_0", "");
            locus.put("A_0", "");
            locus.put("D_0", "");
            Alignment seq = new Alignment(locus);
            alignments.add(seq);
            UltrametricTree ut = new UltrametricTree("(E_0:0.23931999999999998,(D_0:0.19788,A_0:0.19792):0.041440000000000005);", seq);
            ut.updateMutationRate(p[0]);
            geneTrees.add(ut);
            DeltaExchange op = new DeltaExchange(geneTrees);
            ut = geneTrees.get(0);
            System.out.println(ut.getTree().toString());
            double ll = ut.logDensity();
            System.out.println(ll);
        }

        {
            Double[] p = {1.0};

            Utils._PARAMETER_INPUT = Arrays.asList(p);
            List<Alignment> alignments = new ArrayList<>();
            List<UltrametricTree> geneTrees = new ArrayList<>();
            Map<String, String> locus = new HashMap<>();
            locus.put("E_0", "");
            locus.put("A_0", "");
            locus.put("D_0", "");
            Alignment seq = new Alignment(locus);
            alignments.add(seq);
            try{
                STITree tree = new STITree("(E_0:0.23931999999999998,(D_0:0.19788,A_0:0.19792):0.041440000000000005);");
                Trees.scaleBranchLengths(tree, 0.34013311268852675);
                UltrametricTree ut = new UltrametricTree(tree.toString(), seq);
                geneTrees.add(ut);
                DeltaExchange op = new DeltaExchange(geneTrees);
                ut = geneTrees.get(0);
                System.out.println(ut.getTree().toString());
                double ll = ut.logDensity();
                System.out.println(ll);
            }catch (Exception e){

            }


        }




    }

